const trades = $('Fetch Recent Trades').all().map(i => i.json);
const week = $('Fetch Week Stats').all().map(i => i.json);
const wins = week.filter(t => t.win).length;
const wr = week.length ? Math.round(wins/week.length*100) : 0;
const pnls = week.filter(t => t.option_pnl_pct != null).map(t => parseFloat(t.option_pnl_pct));
const avg = pnls.length ? (pnls.reduce((a,b)=>a+b,0)/pnls.length).toFixed(1) : '0';
const tradeLines = trades.slice(0,3).map(t => `${t.ticker} ${t.side} ${t.option_pnl_pct > 0 ? '+' : ''}${parseFloat(t.option_pnl_pct||0).toFixed(1)}% (${t.exit_reason||'auto'})`).join(', ');
const today = new Date().toLocaleDateString('en-US',{weekday:'long',month:'long',day:'numeric'});
return [{ json: {
  today,
  week_trades: week.length,
  week_win_rate: wr,
  week_avg_pnl: avg,
  recent_trades_summary: tradeLines || 'No recent trades',
  day_of_week: new Date().toLocaleDateString('en-US',{weekday:'long'})
}}];

const resp = $json;
const text = resp.content[0].text;
let parsed;
try { parsed = JSON.parse(text); } catch(e) { parsed = { error: text }; }
const today = new Date().toISOString().slice(0,10);
return [{ json: { ...parsed, generated_at: today, status: 'PENDING_APPROVAL' } }];

